   238→
   239→      const url = `${this.config.baseUrl}/os/mxwo`;
   240→
   241→      try {
   242→        const response = await fetch(url, {
   243→          method: 'POST',
   244→          headers: this.buildHeaders(),
   245→          body: JSON.stringify(payload),
   246→          signal: AbortSignal.timeout(this.config.timeoutMs),
