   670→  // ===========================================================================
   671→  // Private Helpers
   672→  // ===========================================================================
   673→
   674→  /**
   675→   * Get or create webhook health record for a depot
   676→   */
   677→  private async getOrCreateHealthRecord(depotId?: string): Promise<MaximoWebhookHealth> {
   678→    // Query for existing record
   679→    const whereClause = depotId
   680→      ? eq(maximoWebhookHealth.depotId, depotId)
