/**
 * MMS Maximo Polling Service
 *
 * Implements polling fallback mechanism for Maximo integration.
 * When webhooks become unreliable (no delivery for configured timeout),
 * this service automatically activates scheduled polling.
 *
 * Key responsibilities:
 * - Monitor webhook health and detect stale connections
 * - Schedule and manage BullMQ repeatable polling jobs
 * - Deduplicate webhook vs polling updates
 * - Track sync mode transitions (WEBHOOK → POLLING → HYBRID)
 *
 * Sync modes:
 * - WEBHOOK: Primary mode, real-time updates via webhooks
 * - POLLING: Fallback mode, scheduled pulls every 15 minutes
 * - HYBRID: Both active during transition periods
 *
 * @see specs/007-integration.md Section 7.4.7
 */

import { eq, sql, isNull } from 'drizzle-orm';
import { Queue } from 'bullmq';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  maximoWebhookHealth,
  maximoIntegrationConfig,
  maximoShadowRecords,
  type MaximoWebhookHealth,
} from '../lib/db/schema';
import {
  QUEUE_NAMES,
  getQueue,
  type MaximoSyncJobData,
} from '../lib/queue';
import {
  maximoMetrics,
  recordPollingFallbackActivation,
  updateSyncModeMetric,
} from '../lib/metrics';
import { getMaximoSyncService, type PullResult } from './maximo-sync';

// =============================================================================
// Types
// =============================================================================

/** Sync mode type */
export type SyncMode = 'WEBHOOK' | 'POLLING' | 'HYBRID';

/** Polling configuration */
export interface PollingConfig {
  enabled: boolean;
  intervalMinutes: number;
  webhookTimeoutMinutes: number;
  gracePeriodMinutes: number;
  deduplicationWindowMs: number;
}

/** Default polling configuration */
export const DEFAULT_POLLING_CONFIG: PollingConfig = {
  enabled: true,
  intervalMinutes: 15,
  webhookTimeoutMinutes: 30,
  gracePeriodMinutes: 5,
  deduplicationWindowMs: 5000,
};

/** Webhook health status */
export interface WebhookHealthStatus {
  isHealthy: boolean;
  lastReceivedAt: Date | null;
  minutesSinceLastWebhook: number | null;
  consecutiveFailures: number;
  syncMode: SyncMode;
  pollingActive: boolean;
}

/** Polling job result */
export interface PollingResult {
  processed: number;
  updated: number;
  conflicts: number;
  errors: number;
  duplicatesPrevented: number;
  durationMs: number;
  syncMode: SyncMode;
}

// =============================================================================
// Constants
// =============================================================================

/** BullMQ repeat job key prefix */
const POLLING_JOB_KEY = 'maximo-polling';

// =============================================================================
// Singleton instance
// =============================================================================

let instance: MaximoPollingService | null = null;

/**
 * Get the singleton MaximoPollingService instance
 */
export function getMaximoPollingService(): MaximoPollingService {
  if (!instance) {
    instance = new MaximoPollingService();
  }
  return instance;
}

// =============================================================================
// MaximoPollingService Implementation
// =============================================================================

/**
 * Maximo Polling Service for fallback synchronization
 *
 * Monitors webhook health and automatically activates polling when
 * webhooks become unreliable. Uses BullMQ repeatable jobs for scheduling.
 *
 * @example
 * ```typescript
 * const pollingService = getMaximoPollingService();
 *
 * // Record successful webhook
 * await pollingService.recordWebhookReceived('wo_status_changed');
 *
 * // Check if polling should be activated
 * const health = await pollingService.getWebhookHealth();
 * if (!health.isHealthy) {
 *   await pollingService.activatePolling();
 * }
 *
 * // Execute polling job
 * const result = await pollingService.executePolling();
 * ```
 */
export class MaximoPollingService extends BaseService {
  private queue: Queue<MaximoSyncJobData>;
  private pollingJobId: string | null = null;

  constructor() {
    super({ name: 'maximo-polling-service' });
    this.queue = getQueue(QUEUE_NAMES.MAXIMO_SYNC);
  }

  // ===========================================================================
  // Webhook Health Tracking
  // ===========================================================================

  /**
   * Record a successful webhook receipt
   *
   * Updates the webhook health record and potentially deactivates polling
   * if the system was in fallback mode.
   */
  async recordWebhookReceived(
    eventType: string,
    depotId?: string
  ): Promise<void> {
    return this.traced('recordWebhookReceived', async (span) => {
      span.setAttribute('webhook.event_type', eventType);
      if (depotId) span.setAttribute(MmsAttributes.DEPOT_ID, depotId);

      const healthRecord = await this.getOrCreateHealthRecord(depotId);
      const now = new Date();

      await this.db
        .update(maximoWebhookHealth)
        .set({
          lastWebhookReceivedAt: now,
          lastWebhookEventType: eventType,
          webhookConsecutiveFailures: 0,
          totalWebhooksReceived: sql`${maximoWebhookHealth.totalWebhooksReceived} + 1`,
          updatedAt: now,
        })
        .where(eq(maximoWebhookHealth.id, healthRecord.id));

      // Check if we should transition from POLLING back to WEBHOOK
      if (healthRecord.syncMode === 'POLLING' || healthRecord.syncMode === 'HYBRID') {
        const config = await this.getPollingConfig(depotId);

        // Enter HYBRID mode for grace period before fully switching back
        if (healthRecord.syncMode === 'POLLING') {
          await this.setSyncMode(healthRecord.id, 'HYBRID', depotId);
          this.log.info(
            { depotId, eventType },
            'Webhook received during polling mode, entering HYBRID mode'
          );
        }

        // Schedule deactivation after grace period
        setTimeout(async () => {
          const currentHealth = await this.getWebhookHealth(depotId);
          if (currentHealth.isHealthy && currentHealth.syncMode === 'HYBRID') {
            await this.deactivatePolling(depotId);
          }
        }, config.gracePeriodMinutes * 60 * 1000);
      }

      this.log.debug({ eventType, depotId }, 'Webhook received recorded');
    });
  }

  /**
   * Record a webhook delivery failure
   */
  async recordWebhookFailure(
    error: string,
    depotId?: string
  ): Promise<void> {
    return this.traced('recordWebhookFailure', async (span) => {
      if (depotId) span.setAttribute(MmsAttributes.DEPOT_ID, depotId);

      const healthRecord = await this.getOrCreateHealthRecord(depotId);
      const now = new Date();
      const newFailureCount = (healthRecord.webhookConsecutiveFailures ?? 0) + 1;

      await this.db
        .update(maximoWebhookHealth)
        .set({
          webhookConsecutiveFailures: newFailureCount,
          webhookLastFailureAt: now,
          webhookLastError: error,
          updatedAt: now,
        })
        .where(eq(maximoWebhookHealth.id, healthRecord.id));

      // Check if we should activate polling
      if (newFailureCount >= 3) {
        this.log.warn(
          { depotId, failures: newFailureCount, error },
          'Multiple webhook failures detected, activating polling'
        );
        await this.activatePolling(depotId, 'circuit_breaker');
      }
    });
  }

  /**
   * Get current webhook health status
   */
  async getWebhookHealth(depotId?: string): Promise<WebhookHealthStatus> {
    return this.traced('getWebhookHealth', async (span) => {
      if (depotId) span.setAttribute(MmsAttributes.DEPOT_ID, depotId);

      const healthRecord = await this.getOrCreateHealthRecord(depotId);
      const config = await this.getPollingConfig(depotId);

      const now = new Date();
      const lastReceived = healthRecord.lastWebhookReceivedAt;
      let minutesSinceLastWebhook: number | null = null;
      let isHealthy = false;

      if (lastReceived) {
        minutesSinceLastWebhook = Math.floor(
          (now.getTime() - lastReceived.getTime()) / (60 * 1000)
        );
        isHealthy = minutesSinceLastWebhook < config.webhookTimeoutMinutes;
      }

      const status: WebhookHealthStatus = {
        isHealthy,
        lastReceivedAt: lastReceived,
        minutesSinceLastWebhook,
        consecutiveFailures: healthRecord.webhookConsecutiveFailures ?? 0,
        syncMode: (healthRecord.syncMode as SyncMode) ?? 'WEBHOOK',
        pollingActive: healthRecord.pollingEnabled ?? false,
      };

      span.setAttribute('webhook.healthy', isHealthy);
      span.setAttribute('webhook.sync_mode', status.syncMode);

      return status;
    });
  }

  /**
   * Check webhook health and activate polling if needed
   *
   * This should be called periodically (e.g., from a scheduled job)
   * to detect webhook timeouts and activate polling automatically.
   */
  async checkAndActivatePollingIfNeeded(depotId?: string): Promise<boolean> {
    return this.traced('checkAndActivatePollingIfNeeded', async (span) => {
      const health = await this.getWebhookHealth(depotId);

      if (!health.isHealthy && !health.pollingActive) {
        this.log.info(
          {
            depotId,
            minutesSinceLastWebhook: health.minutesSinceLastWebhook,
            consecutiveFailures: health.consecutiveFailures,
          },
          'Webhook timeout detected, activating polling fallback'
        );

        await this.activatePolling(depotId, 'webhook_timeout');
        span.setAttribute('polling.activated', true);
        return true;
      }

      span.setAttribute('polling.activated', false);
      return false;
    });
  }

  // ===========================================================================
  // Polling Job Management
  // ===========================================================================

  /**
   * Activate polling fallback
   *
   * Creates a BullMQ repeatable job that executes polling at configured intervals.
   */
  async activatePolling(
    depotId?: string,
    reason: 'webhook_timeout' | 'manual' | 'circuit_breaker' = 'manual'
  ): Promise<void> {
    return this.traced('activatePolling', async (span) => {
      if (depotId) span.setAttribute(MmsAttributes.DEPOT_ID, depotId);
      span.setAttribute('polling.activation_reason', reason);

      const healthRecord = await this.getOrCreateHealthRecord(depotId);
      const config = await this.getPollingConfig(depotId);

      // Update health record
      await this.db
        .update(maximoWebhookHealth)
        .set({
          pollingEnabled: true,
          pollingActivatedAt: new Date(),
          syncMode: 'POLLING',
          totalFallbackActivations: sql`${maximoWebhookHealth.totalFallbackActivations} + 1`,
          updatedAt: new Date(),
        })
        .where(eq(maximoWebhookHealth.id, healthRecord.id));

      // Create repeatable job
      const jobKey = depotId ? `${POLLING_JOB_KEY}-${depotId}` : POLLING_JOB_KEY;

      // Remove existing job if any
      await this.removePollingJob(depotId);

      // Add new repeatable job
      const job = await this.queue.add(
        jobKey,
        {
          operation: 'polling',
          depotId,
          isPollingFallback: true,
          deduplicateWithWebhooks: true,
        },
        {
          repeat: {
            pattern: `*/${config.intervalMinutes} * * * *`, // Every N minutes
          },
          jobId: jobKey,
        }
      );

      this.pollingJobId = job.id ?? null;

      // Record metrics
      recordPollingFallbackActivation(reason);
      updateSyncModeMetric(depotId ?? 'global', 'POLLING');

      this.log.info(
        {
          depotId,
          reason,
          intervalMinutes: config.intervalMinutes,
          jobId: job.id,
        },
        'Polling fallback activated'
      );
    });
  }

  /**
   * Deactivate polling fallback
   */
  async deactivatePolling(depotId?: string): Promise<void> {
    return this.traced('deactivatePolling', async (span) => {
      if (depotId) span.setAttribute(MmsAttributes.DEPOT_ID, depotId);

      const healthRecord = await this.getOrCreateHealthRecord(depotId);

      // Update health record
      await this.db
        .update(maximoWebhookHealth)
        .set({
          pollingEnabled: false,
          syncMode: 'WEBHOOK',
          updatedAt: new Date(),
        })
        .where(eq(maximoWebhookHealth.id, healthRecord.id));

      // Remove repeatable job
      await this.removePollingJob(depotId);

      // Update metrics
      updateSyncModeMetric(depotId ?? 'global', 'WEBHOOK');

      this.log.info({ depotId }, 'Polling fallback deactivated');
    });
  }

  /**
   * Remove the polling repeatable job
   */
  private async removePollingJob(depotId?: string): Promise<void> {
    const jobKey = depotId ? `${POLLING_JOB_KEY}-${depotId}` : POLLING_JOB_KEY;

    try {
      // Get all repeatable jobs and remove matching ones
      const repeatableJobs = await this.queue.getRepeatableJobs();
      for (const job of repeatableJobs) {
        if (job.name === jobKey || job.id === jobKey) {
          await this.queue.removeRepeatableByKey(job.key);
          this.log.debug({ jobKey, repeatKey: job.key }, 'Removed polling repeatable job');
        }
      }
    } catch (error) {
      this.log.warn({ error, jobKey }, 'Failed to remove polling job');
    }
  }

  // ===========================================================================
  // Polling Execution
  // ===========================================================================

  /**
   * Execute a polling sync operation
   *
   * Pulls changes from Maximo and deduplicates against recent webhooks.
   * Returns detailed results including duplicates prevented.
   */
  async executePolling(depotId?: string): Promise<PollingResult> {
    return this.traced('executePolling', async (span) => {
      if (depotId) span.setAttribute(MmsAttributes.DEPOT_ID, depotId);

      const startTime = Date.now();
      const healthRecord = await this.getOrCreateHealthRecord(depotId);
      const config = await this.getPollingConfig(depotId);

      // Get last processed timestamp for deduplication
      const lastProcessedAt = healthRecord.lastProcessedChangeTimestamp;
      let duplicatesPrevented = 0;

      // Execute pull from Maximo
      const maximoService = getMaximoSyncService();
      const pullResult: PullResult = await maximoService.pullFromMaximo();

      // Deduplicate: check if any pulled records were recently updated by webhooks
      if (lastProcessedAt && config.deduplicationWindowMs > 0) {
        const windowStart = new Date(Date.now() - config.deduplicationWindowMs);

        // For each updated record, check if it was updated within the deduplication window
        // If so, it was likely already processed by a webhook
        for (const detail of pullResult.details) {
          if (detail.action === 'UPDATED') {
            const shadowRecord = await this.db.query.maximoShadowRecords.findFirst({
              where: eq(maximoShadowRecords.pmScheduleId, detail.pmScheduleId),
            });

            if (shadowRecord?.updatedAt && shadowRecord.updatedAt > windowStart) {
              duplicatesPrevented++;
              maximoMetrics.duplicatesPrevented.inc();
            }
          }
        }
      }

      // Update health record with poll results
      const now = new Date();
      await this.db
        .update(maximoWebhookHealth)
        .set({
          lastPollAt: now,
          lastPollResult: {
            processed: pullResult.processed,
            updated: pullResult.updated,
            conflicts: pullResult.conflicts,
            errors: pullResult.errors,
            durationMs: Date.now() - startTime,
          },
          lastProcessedChangeTimestamp: now,
          totalPollsExecuted: sql`${maximoWebhookHealth.totalPollsExecuted} + 1`,
          totalDuplicatesPrevented: sql`${maximoWebhookHealth.totalDuplicatesPrevented} + ${duplicatesPrevented}`,
          pollingConsecutiveFailures: pullResult.errors > 0
            ? sql`${maximoWebhookHealth.pollingConsecutiveFailures} + 1`
            : sql`0`,
          updatedAt: now,
        })
        .where(eq(maximoWebhookHealth.id, healthRecord.id));

      // Record metrics
      const durationMs = Date.now() - startTime;
      maximoMetrics.pollingDuration.observe(durationMs / 1000);
      maximoMetrics.pollingRecordsFound.inc(pullResult.processed);

      const result: PollingResult = {
        processed: pullResult.processed,
        updated: pullResult.updated - duplicatesPrevented,
        conflicts: pullResult.conflicts,
        errors: pullResult.errors,
        duplicatesPrevented,
        durationMs,
        syncMode: (healthRecord.syncMode as SyncMode) ?? 'POLLING',
      };

      span.setAttribute('polling.processed', result.processed);
      span.setAttribute('polling.updated', result.updated);
      span.setAttribute('polling.duplicates_prevented', duplicatesPrevented);

      this.log.info(
        {
          depotId,
          processed: result.processed,
          updated: result.updated,
          duplicatesPrevented,
          durationMs,
        },
        'Polling sync completed'
      );

      return result;
    });
  }

  // ===========================================================================
  // Configuration
  // ===========================================================================

  /**
   * Get polling configuration for a depot (or global default)
   */
  async getPollingConfig(depotId?: string): Promise<PollingConfig> {
    return this.traced('getPollingConfig', async () => {
      // Try depot-specific config first
      if (depotId) {
        const depotConfig = await this.db.query.maximoIntegrationConfig.findFirst({
          where: eq(maximoIntegrationConfig.depotId, depotId),
        });

        if (depotConfig) {
          return {
            enabled: depotConfig.syncEnabled ?? true,
            intervalMinutes: depotConfig.pollIntervalMinutes ?? DEFAULT_POLLING_CONFIG.intervalMinutes,
            webhookTimeoutMinutes: DEFAULT_POLLING_CONFIG.webhookTimeoutMinutes,
            gracePeriodMinutes: DEFAULT_POLLING_CONFIG.gracePeriodMinutes,
            deduplicationWindowMs: DEFAULT_POLLING_CONFIG.deduplicationWindowMs,
          };
        }
      }

      // Try global config
      const globalConfig = await this.db.query.maximoIntegrationConfig.findFirst({
        where: isNull(maximoIntegrationConfig.depotId),
      });

      if (globalConfig) {
        return {
          enabled: globalConfig.syncEnabled ?? true,
          intervalMinutes: globalConfig.pollIntervalMinutes ?? DEFAULT_POLLING_CONFIG.intervalMinutes,
          webhookTimeoutMinutes: DEFAULT_POLLING_CONFIG.webhookTimeoutMinutes,
          gracePeriodMinutes: DEFAULT_POLLING_CONFIG.gracePeriodMinutes,
          deduplicationWindowMs: DEFAULT_POLLING_CONFIG.deduplicationWindowMs,
        };
      }

      return DEFAULT_POLLING_CONFIG;
    });
  }

  /**
   * Update polling configuration
   */
  async updatePollingConfig(
    config: Partial<PollingConfig>,
    depotId?: string
  ): Promise<void> {
    return this.traced('updatePollingConfig', async () => {
      const healthRecord = await this.getOrCreateHealthRecord(depotId);

      await this.db
        .update(maximoWebhookHealth)
        .set({
          pollingIntervalMinutes: config.intervalMinutes,
          webhookTimeoutMinutes: config.webhookTimeoutMinutes,
          gracePeriodMinutes: config.gracePeriodMinutes,
          deduplicationWindowMs: config.deduplicationWindowMs,
          updatedAt: new Date(),
        })
        .where(eq(maximoWebhookHealth.id, healthRecord.id));

      // If polling is active, reschedule with new interval
      if (healthRecord.pollingEnabled && config.intervalMinutes) {
        await this.removePollingJob(depotId);
        await this.activatePolling(depotId, 'manual');
      }
    });
  }

  // ===========================================================================
  // Sync Mode Management
  // ===========================================================================

  /**
   * Get current sync mode
   */
  async getSyncMode(depotId?: string): Promise<SyncMode> {
    const healthRecord = await this.getOrCreateHealthRecord(depotId);
    return (healthRecord.syncMode as SyncMode) ?? 'WEBHOOK';
  }

  /**
   * Set sync mode
   */
  private async setSyncMode(
    healthRecordId: string,
    mode: SyncMode,
    depotId?: string
  ): Promise<void> {
    await this.db
      .update(maximoWebhookHealth)
      .set({
        syncMode: mode,
        updatedAt: new Date(),
      })
      .where(eq(maximoWebhookHealth.id, healthRecordId));

    updateSyncModeMetric(depotId ?? 'global', mode);
  }

  // ===========================================================================
  // Statistics
  // ===========================================================================

  /**
   * Get polling statistics
   */
  async getPollingStats(depotId?: string): Promise<{
    webhookHealth: WebhookHealthStatus;
    config: PollingConfig;
    totalPollsExecuted: number;
    totalDuplicatesPrevented: number;
    totalFallbackActivations: number;
    lastPollResult: PollingResult | null;
  }> {
    return this.traced('getPollingStats', async () => {
      const healthRecord = await this.getOrCreateHealthRecord(depotId);
      const config = await this.getPollingConfig(depotId);
      const webhookHealth = await this.getWebhookHealth(depotId);

      return {
        webhookHealth,
        config,
        totalPollsExecuted: healthRecord.totalPollsExecuted ?? 0,
        totalDuplicatesPrevented: healthRecord.totalDuplicatesPrevented ?? 0,
        totalFallbackActivations: healthRecord.totalFallbackActivations ?? 0,
        lastPollResult: healthRecord.lastPollResult as PollingResult | null,
      };
    });
  }

  // ===========================================================================
  // Private Helpers
  // ===========================================================================

  /**
   * Get or create webhook health record for a depot
   */
  private async getOrCreateHealthRecord(depotId?: string): Promise<MaximoWebhookHealth> {
    // Query for existing record
    const whereClause = depotId
      ? eq(maximoWebhookHealth.depotId, depotId)
      : isNull(maximoWebhookHealth.depotId);

    const existing = await this.db.query.maximoWebhookHealth.findFirst({
      where: whereClause,
    });

    if (existing) {
      return existing;
    }

    // Create new record
    const [newRecord] = await this.db
      .insert(maximoWebhookHealth)
      .values({
        depotId: depotId ?? null,
        syncMode: 'WEBHOOK',
        pollingEnabled: false,
      })
      .returning();

    this.log.debug({ depotId }, 'Created new webhook health record');
    return newRecord;
  }
}

