  1294→  private calculateNextRetry(attempts: number): Date {
  1295→    // Exponential backoff with max delay
  1296→    const initialDelayMs = 1000;
  1297→    const backoffMultiplier = 2;
  1298→    const maxDelayMs = 60000;
  1299→
  1300→    const delay = Math.min(
  1301→      initialDelayMs * Math.pow(backoffMultiplier, attempts - 1),
  1302→      maxDelayMs
  1303→    );
  1304→    return addSeconds(new Date(), delay / 1000);
  1305→  }
