/**
 * MMS File Watcher Daemon
 *
 * Monitors a directory for new mileage CSV files and queues them for processing.
 * Uses chokidar for cross-platform file system watching.
 *
 * Usage:
 *   bun run src/file-watcher/daemon.ts
 *
 * Environment Variables:
 *   WATCH_PATH - Directory to watch for new files (default: /data/inbox)
 *   QUARANTINE_PATH - Directory for failed files (default: /data/quarantine)
 *   POLL_INTERVAL_MS - Polling interval in ms (default: 1000)
 *   FILE_PATTERN - Regex pattern for files to process (default: mileage_\\d{8}\\.csv)
 *
 * @see specs/004-domain-services.md Section 4.2
 * @see specs/008-operations.md
 */

import * as chokidar from 'chokidar';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { logger } from '../lib/logging/logger';
import { addJob, QUEUE_NAMES } from '../lib/queue';
import type { IngestionJobData } from '../lib/queue';

// =============================================================================
// Configuration
// =============================================================================

interface FileWatcherConfig {
  watchPath: string;
  quarantinePath: string;
  pollIntervalMs: number;
  filePattern: RegExp;
  stabilityThresholdMs: number;
}

function getConfig(): FileWatcherConfig {
  const watchPath = process.env['WATCH_PATH'] || '/data/inbox';
  const quarantinePath = process.env['QUARANTINE_PATH'] || '/data/quarantine';
  const pollIntervalMs = parseInt(process.env['POLL_INTERVAL_MS'] || '1000', 10);
  const filePatternStr = process.env['FILE_PATTERN'] || 'mileage_\\d{8}\\.csv';
  const stabilityThresholdMs = parseInt(process.env['STABILITY_THRESHOLD_MS'] || '2000', 10);

  return {
    watchPath,
    quarantinePath,
    pollIntervalMs,
    filePattern: new RegExp(`^${filePatternStr}$`),
    stabilityThresholdMs,
  };
}

// =============================================================================
// File Watcher Service
// =============================================================================

const log = logger.child({ module: 'file-watcher' });

class FileWatcherDaemon {
  private config: FileWatcherConfig;
  private watcher: chokidar.FSWatcher | null = null;
  private processing = new Set<string>();
  private isShuttingDown = false;

  constructor(config: FileWatcherConfig) {
    this.config = config;
  }

  async start(): Promise<void> {
    log.info({ config: this.config }, 'Starting file watcher daemon');

    this.ensureDirectoriesExist();
    await this.processExistingFiles();
    this.startWatching();
  }

  async stop(): Promise<void> {
    log.info('Stopping file watcher daemon');
    this.isShuttingDown = true;

    if (this.watcher) {
      await this.watcher.close();
      this.watcher = null;
    }

    log.info('File watcher daemon stopped');
  }

  private ensureDirectoriesExist(): void {
    const dirs = [this.config.watchPath, this.config.quarantinePath];

    for (const dir of dirs) {
      if (!fs.existsSync(dir)) {
        log.info({ path: dir }, 'Creating directory');
        fs.mkdirSync(dir, { recursive: true });
      }
    }
  }

  private async processExistingFiles(): Promise<void> {
    log.info({ path: this.config.watchPath }, 'Processing existing files');

    try {
      const files = fs.readdirSync(this.config.watchPath);
      const matchingFiles = files.filter((f) => this.config.filePattern.test(f));

      log.info({ count: matchingFiles.length }, 'Found existing files to process');

      for (const file of matchingFiles) {
        const filePath = path.join(this.config.watchPath, file);
        await this.queueFile(filePath);
      }
    } catch (error) {
      log.error({ error }, 'Failed to process existing files');
    }
  }

  private startWatching(): void {
    log.info({ path: this.config.watchPath }, 'Starting file system watcher');

    this.watcher = chokidar.watch(this.config.watchPath, {
      persistent: true,
      ignoreInitial: true,
      awaitWriteFinish: {
        stabilityThreshold: this.config.stabilityThresholdMs,
        pollInterval: this.config.pollIntervalMs,
      },
      depth: 0,
      usePolling: false,
    });

    this.watcher.on('add', (filePath: string) => this.handleNewFile(filePath));
    this.watcher.on('error', (error: unknown) => {
      const err = error instanceof Error ? error : new Error(String(error));
      this.handleWatchError(err);
    });
    this.watcher.on('ready', () => log.info('File watcher ready'));
  }

  private async handleNewFile(filePath: string): Promise<void> {
    const fileName = path.basename(filePath);

    if (this.isShuttingDown) {
      log.warn({ fileName }, 'Ignoring file during shutdown');
      return;
    }

    if (!this.config.filePattern.test(fileName)) {
      log.debug({ fileName }, 'Ignoring file - does not match pattern');
      return;
    }

    if (this.processing.has(filePath)) {
      log.debug({ fileName }, 'File already being processed');
      return;
    }

    log.info({ fileName, filePath }, 'New file detected');
    await this.queueFile(filePath);
  }

  private async queueFile(filePath: string): Promise<void> {
    const fileName = path.basename(filePath);

    if (this.processing.has(filePath)) {
      return;
    }

    this.processing.add(filePath);

    try {
      const stats = fs.statSync(filePath);

      if (!stats.isFile()) {
        log.warn({ fileName }, 'Not a regular file, skipping');
        this.processing.delete(filePath);
        return;
      }

      const jobData: IngestionJobData = {
        fileName,
        filePath,
        fileSize: stats.size,
        uploadedBy: 'file-watcher',
      };

      const job = await addJob(QUEUE_NAMES.INGESTION, 'process-mileage-file', jobData, {
        attempts: 3,
        backoff: {
          type: 'exponential',
          delay: 5000,
        },
        removeOnComplete: {
          age: 24 * 60 * 60,
          count: 1000,
        },
        removeOnFail: {
          age: 7 * 24 * 60 * 60,
        },
      });

      log.info(
        {
          fileName,
          jobId: job.id,
          fileSize: stats.size,
        },
        'File queued for processing'
      );
    } catch (error) {
      log.error({ fileName, error }, 'Failed to queue file');
      await this.quarantineFile(filePath, error as Error);
    } finally {
      this.processing.delete(filePath);
    }
  }

  private async quarantineFile(filePath: string, error: Error): Promise<void> {
    const fileName = path.basename(filePath);
    const quarantinePath = path.join(
      this.config.quarantinePath,
      `${Date.now()}_${fileName}`
    );

    try {
      fs.renameSync(filePath, quarantinePath);
      log.warn(
        {
          fileName,
          quarantinePath,
          error: error.message,
        },
        'File moved to quarantine'
      );
    } catch (moveError) {
      log.error(
        {
          fileName,
          quarantinePath,
          error: (moveError as Error).message,
        },
        'Failed to move file to quarantine'
      );
    }
  }

  private handleWatchError(error: Error): void {
    log.error({ error: error.message }, 'File watcher error');
  }
}

// =============================================================================
// Graceful Shutdown
// =============================================================================

let daemon: FileWatcherDaemon | null = null;
let isShuttingDown = false;

async function handleShutdown(signal: string): Promise<void> {
  if (isShuttingDown) {
    log.warn({ signal }, 'Shutdown already in progress');
    return;
  }

  isShuttingDown = true;
  log.info({ signal }, 'Received shutdown signal');

  if (daemon) {
    await daemon.stop();
  }

  process.exit(0);
}

// =============================================================================
// Main Entry Point
// =============================================================================

async function main(): Promise<void> {
  log.info('MMS File Watcher Daemon starting');

  process.on('SIGTERM', () => handleShutdown('SIGTERM'));
  process.on('SIGINT', () => handleShutdown('SIGINT'));

  const config = getConfig();
  daemon = new FileWatcherDaemon(config);

  try {
    await daemon.start();
    log.info('File watcher daemon running. Press Ctrl+C to stop.');
  } catch (error) {
    log.error({ error }, 'Failed to start file watcher daemon');
    process.exit(1);
  }
}

if (import.meta.main) {
  main().catch((error) => {
    console.error('File watcher daemon failed:', error);
    process.exit(1);
  });
}

export { FileWatcherDaemon, getConfig };

/**
 * MMS Notification Service
 *
 * Handles email notifications with:
 * - Per-user notification preferences
 * - Digest modes (IMMEDIATE, DAILY_DIGEST, WEEKLY_DIGEST)
 * - Template rendering with variable interpolation
 * - SMTP delivery with retry logic
 * - Notification history and audit trail
 *
 * Notification Types:
 * - DRIFT_ALERT: Baseline drift threshold exceeded
 * - OVERLOAD_WARNING: Man-hour utilization >100%
 * - PM_REMINDER: PM due within configurable days
 * - BASELINE_PUBLISHED: New baseline published
 * - OPTIMIZER_FAILED: Optimizer job failure
 * - FILE_MISSING: No mileage CSV received
 * - MATERIAL_SHORTAGE: Blocking parts unavailable
 * - UNAVAILABILITY_PM_CONFLICT: PM conflicts with unavailability
 * - FILE_VALIDATION_FAILED: Mileage CSV validation failure
 *
 * @see specs/004-domain-services.md Section 4.12
 * @see specs/007-integration.md Section 7.5
 */

import { eq, and, lt, desc, sql, gte, lte, isNull, type SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  notificationPreferences,
  notificationLog,
  digestBatches,
  notificationTemplates,
  users,
  type NotificationPreference,
  type NotificationLogEntry,
  type DigestBatch,
  type NotificationTemplate,
} from '../lib/db/schema';
import { withRetry, EXTERNAL_SERVICE_RETRY_CONFIG, type RetryConfig } from '../lib/utils/resilience';
import { NotificationError, ExternalServiceError } from '../lib/errors';
import { addJob, QUEUE_NAMES, type NotificationJobData } from '../lib/queue';
import { notificationMetrics } from '../lib/metrics';

// =============================================================================
// Types
// =============================================================================

/**
 * Notification types
 */
export type NotificationType =
  | 'DRIFT_ALERT'
  | 'OVERLOAD_WARNING'
  | 'PM_REMINDER'
  | 'BASELINE_PUBLISHED'
  | 'OPTIMIZER_FAILED'
  | 'FILE_MISSING'
  | 'MATERIAL_SHORTAGE'
  | 'UNAVAILABILITY_PM_CONFLICT'
  | 'FILE_VALIDATION_FAILED'
  | 'PROJECTION_ACCURACY_WARNING';

/**
 * Notification severity levels
 */
export type NotificationSeverity = 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW' | 'INFO';

/**
 * Digest mode options
 */
export type DigestMode = 'IMMEDIATE' | 'DAILY_DIGEST' | 'WEEKLY_DIGEST';

/**
 * Notification delivery status
 */
export type NotificationStatus = 'PENDING' | 'QUEUED' | 'SENT' | 'FAILED' | 'SUPPRESSED';

/**
 * Per-type preference settings
 */
export interface TypePreference {
  enabled: boolean;
  minSeverity?: NotificationSeverity;
  depots?: string[];
  daysBeforeDue?: number;
}

/**
 * User notification preferences
 */
export interface UserPreferences {
  preferences: Record<NotificationType, TypePreference>;
  digestMode: DigestMode;
  digestTime: string;
  timezone: string;
  notificationEmail?: string;
}

/**
 * SMTP configuration
 */
export interface SmtpConfig {
  host: string;
  port: number;
  secure: boolean;
  auth?: {
    user: string;
    pass: string;
  };
  from: {
    name: string;
    address: string;
  };
}

/**
 * Send notification request
 */
export interface SendNotificationRequest {
  type: NotificationType;
  severity: NotificationSeverity;
  recipients: string[]; // User IDs or email addresses
  template: string;
  subject: string;
  data: Record<string, unknown>;
  trainId?: string;
  depotId?: string;
  baselineId?: string;
  pmScheduleId?: string;
}

/**
 * Send notification result
 */
export interface SendNotificationResult {
  notificationIds: string[];
  queued: number;
  suppressed: number;
  immediate: number;
  digested: number;
}

/**
 * Email content for SMTP
 */
export interface EmailContent {
  to: string;
  from: { name: string; address: string };
  subject: string;
  html: string;
  text?: string;
}

/**
 * Notification log filters
 */
export interface NotificationLogFilters {
  userId?: string;
  type?: NotificationType;
  severity?: NotificationSeverity;
  status?: NotificationStatus;
  startDate?: string;
  endDate?: string;
}

/**
 * Pagination options
 */
export interface PaginationOptions {
  page: number;
  pageSize: number;
}

/**
 * Paginated result
 */
export interface PaginatedResult<T> {
  data: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

