/**
 * Singleton instance
 */
let notificationServiceInstance: NotificationService | null = null;

/**
 * Get the singleton NotificationService instance
 */
export function getNotificationService(): NotificationService {
  if (!notificationServiceInstance) {
    notificationServiceInstance = new NotificationService();
  }
  return notificationServiceInstance;
}

/**
 * Notification Service
 *
 * Handles all notification operations including:
 * - User preference management
 * - Notification sending with preference checking
 * - Digest batching and processing
 * - SMTP email delivery with retry logic
 */
export class NotificationService extends BaseService {
  private smtpConfig: SmtpConfig;
  private retryConfig: RetryConfig;

  constructor() {
    super({ name: 'notification-service' });

    // Initialize SMTP config from environment
    this.smtpConfig = {
      host: process.env['SMTP_HOST'] ?? 'localhost',
      port: parseInt(process.env['SMTP_PORT'] ?? '587', 10),
      secure: process.env['SMTP_SECURE'] === 'true',
      auth: process.env['SMTP_USER']
        ? {
            user: process.env['SMTP_USER'],
            pass: process.env['SMTP_PASS'] ?? '',
          }
        : undefined,
      from: {
        name: process.env['SMTP_FROM_NAME'] ?? 'MMS Notifications',
        address: process.env['SMTP_FROM_ADDRESS'] ?? 'mms-noreply@metro.example',
      },
    };

    // Use external service retry config for email
    this.retryConfig = {
      ...EXTERNAL_SERVICE_RETRY_CONFIG,
      maxAttempts: 3,
      initialDelayMs: 5000,
      maxDelayMs: 30000,
    };
  }

  // ===========================================================================
  // Template Management
  // ===========================================================================

  /**
   * Get a notification template by name
   *
   * Template lookup hierarchy (first match wins):
   * 1. Depot-specific template (if depotId provided)
   * 2. Global template (depotId = NULL)
   * 3. Default hardcoded template
   *
   * @param templateName Template name (e.g., 'drift_alert', 'pm_reminder')
   * @param depotId Optional depot ID for depot-specific override
   * @returns Template content and subject, or defaults if not found
   */
  async getTemplate(
    templateName: string,
    depotId?: string
  ): Promise<{ subjectTemplate: string; bodyHtml: string; bodyText?: string }> {
    return this.traced('getTemplate', async (span) => {
      span.setAttribute('template.name', templateName);
      if (depotId) span.setAttribute('depot.id', depotId);

      // Try depot-specific template first
      if (depotId) {
        const depotTemplate = await this.db.query.notificationTemplates.findFirst({
          where: and(
            eq(notificationTemplates.name, templateName),
            eq(notificationTemplates.depotId, depotId),
            eq(notificationTemplates.isActive, true)
          ),
        });

        if (depotTemplate) {
          span.setAttribute('template.source', 'depot');
          return {
            subjectTemplate: depotTemplate.subjectTemplate,
            bodyHtml: depotTemplate.bodyHtml,
            bodyText: depotTemplate.bodyText ?? undefined,
          };
        }
      }

      // Try global template
      const globalTemplate = await this.db.query.notificationTemplates.findFirst({
        where: and(
          eq(notificationTemplates.name, templateName),
          isNull(notificationTemplates.depotId),
          eq(notificationTemplates.isActive, true)
        ),
      });

      if (globalTemplate) {
        span.setAttribute('template.source', 'global');
        return {
          subjectTemplate: globalTemplate.subjectTemplate,
          bodyHtml: globalTemplate.bodyHtml,
          bodyText: globalTemplate.bodyText ?? undefined,
        };
      }

      // Fall back to hardcoded defaults
      const defaultBody = DEFAULT_TEMPLATES[templateName] ?? DEFAULT_TEMPLATES['drift_alert'];
      span.setAttribute('template.source', 'default');
      return {
        subjectTemplate: 'MMS {{type}} Notification',
        bodyHtml: defaultBody,
      };
    });
  }

  /**
   * List all notification templates with optional filtering
   */
  async listTemplates(options?: {
    type?: NotificationType;
    depotId?: string;
    activeOnly?: boolean;
  }): Promise<NotificationTemplate[]> {
    return this.traced('listTemplates', async () => {
      const conditions: SQL[] = [];

      if (options?.type) {
        conditions.push(eq(notificationTemplates.type, options.type));
      }
      if (options?.depotId) {
        conditions.push(eq(notificationTemplates.depotId, options.depotId));
      }
      if (options?.activeOnly !== false) {
        conditions.push(eq(notificationTemplates.isActive, true));
      }

      return this.db.query.notificationTemplates.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: [notificationTemplates.type, notificationTemplates.name],
      });
    });
  }

  /**
   * Create or update a notification template
   */
  async upsertTemplate(
    template: {
      name: string;
      type: NotificationType;
      subjectTemplate: string;
      bodyHtml: string;
      bodyText?: string;
      description?: string;
      variables?: Array<{ name: string; description: string }>;
      depotId?: string;
    },
    userId?: string
  ): Promise<NotificationTemplate> {
    return this.traced('upsertTemplate', async (span) => {
      span.setAttribute('template.name', template.name);
      span.setAttribute('template.type', template.type);

      // Check for existing template with same name and depot
      const existing = await this.db.query.notificationTemplates.findFirst({
        where: and(
          eq(notificationTemplates.name, template.name),
          template.depotId
            ? eq(notificationTemplates.depotId, template.depotId)
            : isNull(notificationTemplates.depotId)
        ),
      });

      if (existing) {
        // Update existing template
        const [updated] = await this.db
          .update(notificationTemplates)
          .set({
            type: template.type,
            subjectTemplate: template.subjectTemplate,
            bodyHtml: template.bodyHtml,
            bodyText: template.bodyText,
            description: template.description,
            variables: template.variables ?? [],
            version: sql`${notificationTemplates.version} + 1`,
            updatedAt: new Date(),
            updatedBy: userId,
          })
          .where(eq(notificationTemplates.id, existing.id))
          .returning();
        return updated;
      } else {
        // Create new template
        const [created] = await this.db
          .insert(notificationTemplates)
          .values({
            name: template.name,
            type: template.type,
            subjectTemplate: template.subjectTemplate,
            bodyHtml: template.bodyHtml,
            bodyText: template.bodyText,
            description: template.description,
            variables: template.variables ?? [],
            depotId: template.depotId,
            createdBy: userId,
            updatedBy: userId,
          })
          .returning();
        return created;
      }
    });
  }

  /**
   * Delete a notification template
   */
  async deleteTemplate(templateId: string): Promise<boolean> {
    return this.traced('deleteTemplate', async (span) => {
      span.setAttribute('template.id', templateId);

      const result = await this.db
        .delete(notificationTemplates)
        .where(eq(notificationTemplates.id, templateId))
        .returning({ id: notificationTemplates.id });

      return result.length > 0;
    });
  }

  // ===========================================================================
  // User Preferences
  // ===========================================================================

  /**
   * Get user notification preferences
   */
  async getUserPreferences(userId: string): Promise<UserPreferences | null> {
    return this.traced('getUserPreferences', async (span) => {
      span.setAttribute(MmsAttributes.USER_ID, userId);

      const result = await this.db.query.notificationPreferences.findFirst({
        where: eq(notificationPreferences.userId, userId),
      });

      if (!result) return null;

      return {
        preferences: result.preferences as Record<NotificationType, TypePreference>,
        digestMode: result.digestMode as DigestMode,
        digestTime: result.digestTime ?? '09:00',
        timezone: result.timezone ?? 'Asia/Hong_Kong',
        notificationEmail: result.notificationEmail ?? undefined,
      };
    });
  }

  /**
   * Create or update user notification preferences
   */
  async setUserPreferences(
    userId: string,
    preferences: Partial<UserPreferences>
  ): Promise<NotificationPreference> {
    return this.traced('setUserPreferences', async (span) => {
      span.setAttribute(MmsAttributes.USER_ID, userId);

      const existing = await this.db.query.notificationPreferences.findFirst({
        where: eq(notificationPreferences.userId, userId),
      });

      if (existing) {
        // Update existing
        const [updated] = await this.db
          .update(notificationPreferences)
          .set({
            preferences: preferences.preferences ?? existing.preferences,
            digestMode: preferences.digestMode ?? existing.digestMode,
            digestTime: preferences.digestTime ?? existing.digestTime,
            timezone: preferences.timezone ?? existing.timezone,
            notificationEmail: preferences.notificationEmail ?? existing.notificationEmail,
            updatedAt: new Date(),
          })
          .where(eq(notificationPreferences.id, existing.id))
          .returning();
        return updated;
      } else {
        // Create new
        const defaultPrefs: Record<NotificationType, TypePreference> = {
          DRIFT_ALERT: { enabled: true, minSeverity: 'MEDIUM' },
          OVERLOAD_WARNING: { enabled: true, depots: [] },
          PM_REMINDER: { enabled: true, daysBeforeDue: 7 },
          BASELINE_PUBLISHED: { enabled: true },
          OPTIMIZER_FAILED: { enabled: true },
          FILE_MISSING: { enabled: true },
          MATERIAL_SHORTAGE: { enabled: true },
          UNAVAILABILITY_PM_CONFLICT: { enabled: true },
          FILE_VALIDATION_FAILED: { enabled: true },
          PROJECTION_ACCURACY_WARNING: { enabled: true, minSeverity: 'MEDIUM' },
        };

        const [created] = await this.db
          .insert(notificationPreferences)
          .values({
            userId,
            preferences: preferences.preferences ?? defaultPrefs,
            digestMode: preferences.digestMode ?? 'IMMEDIATE',
            digestTime: preferences.digestTime ?? '09:00',
            timezone: preferences.timezone ?? 'Asia/Hong_Kong',
            notificationEmail: preferences.notificationEmail,
          })
          .returning();
        return created;
      }
    });
  }

  // ===========================================================================
  // Notification Sending
  // ===========================================================================

  /**
   * Send notifications to recipients
   *
   * Handles:
   * - User preference checking (enabled, severity filter, depot filter)
   * - Digest batching based on user preferences
   * - Immediate delivery for CRITICAL notifications
   * - Template rendering
   */
  async sendNotification(request: SendNotificationRequest): Promise<SendNotificationResult> {
    return this.traced('sendNotification', async (span) => {
      span.setAttribute('notification.type', request.type);
      span.setAttribute('notification.severity', request.severity);
      span.setAttribute('notification.recipients', request.recipients.length);

      const result: SendNotificationResult = {
        notificationIds: [],
        queued: 0,
        suppressed: 0,
        immediate: 0,
        digested: 0,
      };

      // Resolve recipients (convert user IDs to emails, fetch preferences)
      const resolvedRecipients = await this.resolveRecipients(request.recipients);

      for (const recipient of resolvedRecipients) {
        // Check if notification should be sent based on preferences
        const { shouldSend, reason } = this.shouldSendNotification(
          recipient.preferences,
          request.type,
          request.severity,
          request.depotId
        );

        if (!shouldSend) {
          // Record suppressed notification
          const [logEntry] = await this.db
            .insert(notificationLog)
            .values({
              userId: recipient.userId,
              recipientEmail: recipient.email,
              type: request.type,
              severity: request.severity,
              template: request.template,
              subject: request.subject,
              data: request.data,
              status: 'SUPPRESSED',
              trainId: request.trainId,
              depotId: request.depotId,
              baselineId: request.baselineId,
              pmScheduleId: request.pmScheduleId,
              errorMessage: reason,
            })
            .returning();

          result.notificationIds.push(logEntry.id);
          result.suppressed++;
          continue;
        }

        // Determine delivery mode
        const isCritical = request.severity === 'CRITICAL';
        const isImmediate = isCritical || recipient.preferences?.digestMode === 'IMMEDIATE';

        if (isImmediate) {
          // Queue for immediate delivery
          const [logEntry] = await this.db
            .insert(notificationLog)
            .values({
              userId: recipient.userId,
              recipientEmail: recipient.email,
              type: request.type,
              severity: request.severity,
              template: request.template,
              subject: request.subject,
              data: request.data,
              status: 'QUEUED',
              trainId: request.trainId,
              depotId: request.depotId,
              baselineId: request.baselineId,
              pmScheduleId: request.pmScheduleId,
            })
            .returning();

          // Queue the notification job
          await addJob<NotificationJobData>(
            QUEUE_NAMES.NOTIFICATION,
            'send-email',
            {
              type: 'email',
              template: request.template,
              recipients: [recipient.email],
              data: {
                ...request.data,
                notificationLogId: logEntry.id,
              },
              priority: request.severity === 'CRITICAL' ? 'high' : 'normal',
            },
            {
              priority: request.severity === 'CRITICAL' ? 1 : 10,
            }
          );

          result.notificationIds.push(logEntry.id);
          result.immediate++;
          result.queued++;
        } else {
          // Add to digest batch
          const digestBatch = await this.getOrCreateDigestBatch(
            recipient.userId!,
            recipient.preferences!.digestMode,
            recipient.preferences!.digestTime,
            recipient.preferences!.timezone
          );

          const [logEntry] = await this.db
            .insert(notificationLog)
            .values({
              userId: recipient.userId,
              recipientEmail: recipient.email,
              type: request.type,
              severity: request.severity,
              template: request.template,
              subject: request.subject,
              data: request.data,
              status: 'PENDING',
              digestBatchId: digestBatch.id,
              isDigested: true,
              trainId: request.trainId,
              depotId: request.depotId,
              baselineId: request.baselineId,
              pmScheduleId: request.pmScheduleId,
            })
            .returning();

          // Update batch count
          await this.db
            .update(digestBatches)
            .set({
              notificationCount: sql`${digestBatches.notificationCount} + 1`,
            })
            .where(eq(digestBatches.id, digestBatch.id));

          result.notificationIds.push(logEntry.id);
          result.digested++;
        }
      }

      // Update metrics
      notificationMetrics.notificationsQueued.inc({ type: request.type, severity: request.severity }, result.queued);

      return result;
    });
  }

  /**
   * Resolve recipients from user IDs or email addresses
   */
  private async resolveRecipients(
    recipients: string[]
  ): Promise<Array<{ userId?: string; email: string; preferences?: UserPreferences }>> {
    const result: Array<{ userId?: string; email: string; preferences?: UserPreferences }> = [];

    for (const recipient of recipients) {
      // Check if it's a UUID (user ID) or email
      const isEmail = recipient.includes('@');

      if (isEmail) {
        // Direct email - no user preferences
        result.push({ email: recipient });
      } else {
        // User ID - fetch user and preferences
        const user = await this.db.query.users.findFirst({
          where: eq(users.id, recipient),
        });

        if (!user) {
          this.log.warn({ userId: recipient }, 'User not found for notification');
          continue;
        }

        const prefs = await this.getUserPreferences(recipient);
        result.push({
          userId: recipient,
          email: prefs?.notificationEmail ?? user.email,
          preferences: prefs ?? undefined,
        });
      }
    }

    return result;
  }

  /**
   * Check if notification should be sent based on preferences
   */
  private shouldSendNotification(
    preferences: UserPreferences | undefined,
    type: NotificationType,
    severity: NotificationSeverity,
    depotId?: string
  ): { shouldSend: boolean; reason?: string } {
    // No preferences = send everything
    if (!preferences) {
      return { shouldSend: true };
    }

    const typePref = preferences.preferences[type];
    if (!typePref) {
      return { shouldSend: true };
    }

    // Check if type is enabled
    if (!typePref.enabled) {
      return { shouldSend: false, reason: `Notification type ${type} is disabled` };
    }

    // Check severity filter
    if (typePref.minSeverity) {
      const severityOrder: NotificationSeverity[] = ['LOW', 'INFO', 'MEDIUM', 'HIGH', 'CRITICAL'];
      const minIndex = severityOrder.indexOf(typePref.minSeverity);
      const currentIndex = severityOrder.indexOf(severity);
      if (currentIndex < minIndex) {
        return {
          shouldSend: false,
          reason: `Severity ${severity} below minimum ${typePref.minSeverity}`,
        };
      }
    }

    // Check depot filter (for OVERLOAD_WARNING)
    if (typePref.depots && typePref.depots.length > 0 && depotId) {
      if (!typePref.depots.includes(depotId)) {
        return { shouldSend: false, reason: `Depot ${depotId} not in allowed list` };
      }
    }

    return { shouldSend: true };
  }

  /**
   * Get or create a digest batch for the user
   */
  private async getOrCreateDigestBatch(
    userId: string,
    digestMode: DigestMode,
    digestTime: string,
    timezone: string
  ): Promise<DigestBatch> {
    // Calculate next scheduled time based on digest mode
    const scheduledFor = this.calculateNextDigestTime(digestMode, digestTime, timezone);

    // Check for existing batch
    const existing = await this.db.query.digestBatches.findFirst({
      where: and(
        eq(digestBatches.userId, userId),
        eq(digestBatches.scheduledFor, scheduledFor),
        eq(digestBatches.status, 'PENDING')
      ),
    });

    if (existing) return existing;

    // Create new batch
    const [batch] = await this.db
      .insert(digestBatches)
      .values({
        userId,
        digestMode,
        scheduledFor,
        status: 'PENDING',
        notificationCount: 0,
      })
      .returning();

    return batch;
  }

  /**
   * Calculate next digest delivery time
   */
  private calculateNextDigestTime(
    digestMode: DigestMode,
    digestTime: string,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    timezone: string
  ): Date {
    const now = new Date();
    const [hours, minutes] = digestTime.split(':').map(Number);

    // Start with today at digest time
    const scheduled = new Date(now);
    scheduled.setHours(hours, minutes, 0, 0);

    // If time has passed today, move to next period
    if (scheduled <= now) {
      if (digestMode === 'DAILY_DIGEST') {
        scheduled.setDate(scheduled.getDate() + 1);
      } else if (digestMode === 'WEEKLY_DIGEST') {
        // Move to next Monday
        const daysUntilMonday = (8 - scheduled.getDay()) % 7 || 7;
        scheduled.setDate(scheduled.getDate() + daysUntilMonday);
      }
    } else if (digestMode === 'WEEKLY_DIGEST') {
      // Find next Monday at digest time
      const dayOfWeek = scheduled.getDay();
      if (dayOfWeek !== 1) {
        const daysUntilMonday = (8 - dayOfWeek) % 7 || 7;
        scheduled.setDate(scheduled.getDate() + daysUntilMonday);
      }
    }

    return scheduled;
  }

  // ===========================================================================
  // Email Delivery
  // ===========================================================================

  /**
   * Send an email immediately (called by notification worker)
   */
  async deliverEmail(
    notificationLogId: string,
    template: string,
    recipient: string,
    data: Record<string, unknown>
  ): Promise<{ success: boolean; messageId?: string; error?: string }> {
    return this.traced('deliverEmail', async (span) => {
      span.setAttribute('notification.log_id', notificationLogId);
      span.setAttribute('notification.recipient', recipient);

      try {
        // Get template content from database (with fallback to defaults)
        const depotId = (data['depotId'] as string) ?? undefined;
        const templateData = await this.getTemplate(template, depotId);

        // Render subject and body
        const subject = renderTemplate(
          (data['subject'] as string) ?? templateData.subjectTemplate,
          { ...data, type: template.replace('_', ' ').toUpperCase() }
        );
        const html = renderTemplate(templateData.bodyHtml, data);

        // Send email
        const result = await sendEmail(
          {
            to: recipient,
            from: this.smtpConfig.from,
            subject,
            html,
          },
          this.smtpConfig,
          this.retryConfig
        );

        // Update notification log
        await this.db
          .update(notificationLog)
          .set({
            status: 'SENT',
            sentAt: new Date(),
          })
          .where(eq(notificationLog.id, notificationLogId));

        // Update metrics
        notificationMetrics.notificationsSent.inc({ template, status: 'success' });

        return { success: true, messageId: result.messageId };
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);

        // Update notification log with failure
        await this.db
          .update(notificationLog)
          .set({
            status: 'FAILED',
            errorMessage,
            retryCount: sql`${notificationLog.retryCount} + 1`,
            lastRetryAt: new Date(),
          })
          .where(eq(notificationLog.id, notificationLogId));

        // Update metrics
        notificationMetrics.notificationsSent.inc({ template, status: 'failed' });

        this.log.error({ notificationLogId, error }, 'Failed to deliver email');

        return { success: false, error: errorMessage };
      }
    });
  }

  /**
   * Process pending digest batches
   * Called by scheduled job (notification worker)
   */
  async processDigestBatches(): Promise<{ processed: number; sent: number; failed: number }> {
    return this.traced('processDigestBatches', async (span) => {
      const now = new Date();
      const result = { processed: 0, sent: 0, failed: 0 };

      // Find pending batches that are due
      const dueBatches = await this.db.query.digestBatches.findMany({
        where: and(
          eq(digestBatches.status, 'PENDING'),
          lt(digestBatches.scheduledFor, now)
        ),
      });

      span.setAttribute('batches.due', dueBatches.length);

      for (const batch of dueBatches) {
        try {
          await this.processDigestBatch(batch);
          result.processed++;
          result.sent++;
        } catch (error) {
          this.log.error({ batchId: batch.id, error }, 'Failed to process digest batch');
          result.processed++;
          result.failed++;
        }
      }

      return result;
    });
  }

  /**
   * Process a single digest batch
   */
  private async processDigestBatch(batch: DigestBatch): Promise<void> {
    // Get all notifications in this batch
    const notifications = await this.db.query.notificationLog.findMany({
      where: eq(notificationLog.digestBatchId, batch.id),
      orderBy: desc(notificationLog.createdAt),
    });

    if (notifications.length === 0) {
      // Empty batch, mark as processed
      await this.db
        .update(digestBatches)
        .set({ status: 'SENT', processedAt: new Date() })
        .where(eq(digestBatches.id, batch.id));
      return;
    }

    // Get user email
    const user = await this.db.query.users.findFirst({
      where: eq(users.id, batch.userId),
    });

    if (!user) {
      throw new NotificationError(`User not found for digest batch: ${batch.userId}`);
    }

    // Get preferences for email address
    const prefs = await this.getUserPreferences(batch.userId);
    const email = prefs?.notificationEmail ?? user.email;

    // Group notifications by type
    const sections: Array<{
      type: string;
      count: number;
      items: Array<{ summary: string }>;
    }> = [];

    const byType = new Map<string, NotificationLogEntry[]>();
    for (const n of notifications) {
      const existing = byType.get(n.type) ?? [];
      existing.push(n);
      byType.set(n.type, existing);
    }

    for (const [type, items] of byType) {
      sections.push({
        type,
        count: items.length,
        items: items.map((item) => ({
          summary: (item.data as Record<string, unknown>)['summary'] as string ?? item.subject ?? type,
        })),
      });
    }

    // Render digest template
    const digestPeriod = batch.digestMode === 'DAILY_DIGEST' ? 'Last 24 hours' : 'Last 7 days';
    const html = renderTemplate(DEFAULT_TEMPLATES['digest'], {
      digestPeriod,
      totalCount: notifications.length,
      sections,
      dashboardUrl: process.env['MMS_DASHBOARD_URL'] ?? 'https://mms.metro.example',
    });

    // Send digest email
    await sendEmail(
      {
        to: email,
        from: this.smtpConfig.from,
        subject: `MMS ${digestPeriod} Digest - ${notifications.length} notifications`,
        html,
      },
      this.smtpConfig,
      this.retryConfig
    );

    // Update all notifications as sent
    await this.db
      .update(notificationLog)
      .set({ status: 'SENT', sentAt: new Date() })
      .where(eq(notificationLog.digestBatchId, batch.id));

    // Mark batch as processed
    await this.db
      .update(digestBatches)
      .set({ status: 'SENT', processedAt: new Date() })
      .where(eq(digestBatches.id, batch.id));
  }

  // ===========================================================================
  // Query Operations
  // ===========================================================================

  /**
   * Get notification history for a user
   */
  async getNotificationHistory(
    filters: NotificationLogFilters,
    pagination: PaginationOptions
  ): Promise<PaginatedResult<NotificationLogEntry>> {
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    return this.traced('getNotificationHistory', async (_span) => {
      const conditions: SQL[] = [];

      if (filters.userId) {
        conditions.push(eq(notificationLog.userId, filters.userId));
      }
      if (filters.type) {
        conditions.push(eq(notificationLog.type, filters.type));
      }
      if (filters.severity) {
        conditions.push(eq(notificationLog.severity, filters.severity));
      }
      if (filters.status) {
        conditions.push(eq(notificationLog.status, filters.status));
      }
      if (filters.startDate) {
        conditions.push(gte(notificationLog.createdAt, new Date(filters.startDate)));
      }
      if (filters.endDate) {
        conditions.push(lte(notificationLog.createdAt, new Date(filters.endDate)));
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      const [data, countResult] = await Promise.all([
        this.db.query.notificationLog.findMany({
          where: whereClause,
          orderBy: desc(notificationLog.createdAt),
          limit: pagination.pageSize,
          offset: (pagination.page - 1) * pagination.pageSize,
        }),
        this.db
          .select({ count: sql<number>`count(*)` })
          .from(notificationLog)
          .where(whereClause),
      ]);

      const total = Number(countResult[0]?.count ?? 0);

      return {
        data,
        total,
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalPages: Math.ceil(total / pagination.pageSize),
      };
    });
  }

  /**
   * Retry failed notifications
   */
  async retryFailedNotifications(maxRetries = 3): Promise<{ retried: number; succeeded: number }> {
    return this.traced('retryFailedNotifications', async (span) => {
      const failed = await this.db.query.notificationLog.findMany({
        where: and(
          eq(notificationLog.status, 'FAILED'),
          sql`${notificationLog.retryCount} < ${maxRetries}`
        ),
        limit: 100,
      });

      span.setAttribute('failed.count', failed.length);

      let succeeded = 0;
      for (const notification of failed) {
        const result = await this.deliverEmail(
          notification.id,
          notification.template,
          notification.recipientEmail,
          notification.data as Record<string, unknown>
        );

        if (result.success) succeeded++;
      }

      return { retried: failed.length, succeeded };
    });
  }

  /**
   * Clean up old notification logs
   */
  async cleanupOldLogs(retentionDays = 90): Promise<number> {
    return this.traced('cleanupOldLogs', async (span) => {
      const cutoff = new Date();
      cutoff.setDate(cutoff.getDate() - retentionDays);

      const result = await this.db
        .delete(notificationLog)
        .where(lt(notificationLog.createdAt, cutoff))
        .returning({ id: notificationLog.id });

      span.setAttribute('deleted.count', result.length);

      return result.length;
    });
  }
}

// Export types
export type { NotificationPreference, NotificationLogEntry, DigestBatch };

