  1160→/**
  1161→ * POST /integration/validate-edit
  1162→ *
  1163→ * Validate if a PM can be edited (not locked by Maximo).
  1164→ *
  1165→ * This should be called before any PM modification operation to check:
  1166→ * 1. Maximo status lock (INPRG, COMP, CLOSE, CAN → read-only)
  1167→ * 2. Sync conflict (unresolved conflict → must resolve first)
  1168→ * 3. Baseline lock (locked in published baseline → needs scenario)
  1169→ *
  1170→ * @body pmScheduleId - PM schedule ID to validate
  1171→ * @returns Validation result with reason if invalid
  1172→ */
  1173→integrationRoutes.post('/integration/validate-edit', async (c) => {
  1174→  const requestId = getRequestId(c);
  1175→  const service = getService();
  1176→
  1177→  let body: { pmScheduleId: string };
  1178→
  1179→  try {
  1180→    body = await c.req.json();
  1181→  } catch {
  1182→    return c.json(
  1183→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
  1184→      400
  1185→    );
  1186→  }
  1187→
  1188→  if (!body.pmScheduleId || !isValidUuid(body.pmScheduleId)) {
  1189→    return c.json(
  1190→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid or missing pmScheduleId', requestId),
  1191→      400
  1192→    );
  1193→  }
  1194→
  1195→  try {
  1196→    const validation = await service.validateEdit(body.pmScheduleId);
  1197→
  1198→    if (!validation.valid) {
  1199→      // Return 423 Locked for Maximo status lock
  1200→      if (validation.reason === 'MAXIMO_STATUS_LOCK') {
  1201→        return c.json(
  1202→          error(
  1203→            ErrorCodes.MAXIMO_LOCK,
  1204→            validation.message ?? 'PM is locked by Maximo',
  1205→            requestId,
  1206→            {
  1207→              reason: validation.reason,
  1208→              maximoStatus: validation.maximoStatus,
  1209→              maximoWoNum: validation.maximoWoNum,
  1210→              suggestion: validation.suggestion,
  1211→            }
  1212→          ),
  1213→          423
  1214→        );
  1215→      }
  1216→
  1217→      // Return 409 Conflict for sync conflict
  1218→      if (validation.reason === 'SYNC_CONFLICT') {
  1219→        return c.json(
  1220→          error(
  1221→            ErrorCodes.CONFLICT,
  1222→            validation.message ?? 'Unresolved sync conflict',
  1223→            requestId,
  1224→            {
  1225→              reason: validation.reason,
  1226→              suggestion: validation.suggestion,
  1227→            }
  1228→          ),
  1229→          409
  1230→        );
  1231→      }
  1232→
  1233→      // Return 423 for baseline lock
  1234→      if (validation.reason === 'BASELINE_LOCK') {
  1235→        return c.json(
  1236→          error(
  1237→            ErrorCodes.BASELINE_LOCK,
  1238→            validation.message ?? 'PM is locked in published baseline',
  1239→            requestId,
  1240→            {
  1241→              reason: validation.reason,
  1242→              suggestion: validation.suggestion,
  1243→            }
  1244→          ),
  1245→          423
  1246→        );
  1247→      }
  1248→
  1249→      // Return 404 for not found
  1250→      return c.json(
  1251→        error(ErrorCodes.NOT_FOUND, validation.message ?? 'PM not found', requestId),
  1252→        404
  1253→      );
  1254→    }
  1255→
  1256→    return c.json(
  1257→      success({
  1258→        valid: true,
  1259→        pmScheduleId: body.pmScheduleId,
  1260→        message: 'PM can be edited',
  1261→      }, { timing: { durationMs: getRequestDuration(c) } })
  1262→    );
  1263→  } catch (err) {
  1264→    logger.error({ requestId, error: err }, 'Failed to validate edit');
  1265→    return c.json(
  1266→      error(ErrorCodes.INTERNAL_ERROR, 'Failed to validate edit', requestId),
  1267→      500
  1268→    );
  1269→  }
  1270→});
