/**
 * Integration Routes
 *
 * REST endpoints for Maximo integration, including:
 * - Webhook receiver for CM status updates from Maximo
 * - Sync operations (push, pull, full)
 * - Conflict management
 * - Sync statistics
 *
 * Integration flow:
 * 1. Maximo sends webhook on WO status change → POST /integration/webhooks/maximo
 * 2. MMS updates shadow record and PM status
 * 3. For proactive sync: POST /integration/sync/pull
 * 4. Conflicts are resolved via POST /integration/conflicts/:id/resolve
 *
 * @see specs/007-integration.md
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  ErrorCodes,
  parsePaginationQuery,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getMaximoSyncService,
  getMaximoPollingService,
  type ConflictResolution,
  type MaximoWoStatus,
  MAXIMO_TO_MMS_STATUS,
  MAXIMO_STATUS_LABELS,
  LOCKED_MAXIMO_STATUSES,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';
import { NotFoundError, ValidationError } from '../../lib/errors';
import { logger } from '../../lib/logging/logger';
import { eq } from 'drizzle-orm';
import { maximoShadowRecords, pmSchedule } from '../../lib/db/schema';
import { db } from '../../lib/db/connection';

// Singleton service instances
let maximoSyncService: ReturnType<typeof getMaximoSyncService> | null = null;
let maximoPollingService: ReturnType<typeof getMaximoPollingService> | null = null;

function getService(): ReturnType<typeof getMaximoSyncService> {
  if (!maximoSyncService) {
    maximoSyncService = getMaximoSyncService();
  }
  return maximoSyncService;
}

function getPollingService(): ReturnType<typeof getMaximoPollingService> {
  if (!maximoPollingService) {
    maximoPollingService = getMaximoPollingService();
  }
  return maximoPollingService;
}

export const integrationRoutes = new Hono<{ Variables: AppVariables }>();

// =============================================================================
// Webhook Endpoints
// =============================================================================

/**
 * Maximo Webhook Event Types
 */
type MaximoWebhookEventType =
  | 'wo_status_changed'
  | 'wo_created'
  | 'wo_updated'
  | 'wo_cancelled';

/**
 * Maximo Webhook Payload
 *
 * Payload sent by Maximo when a work order status changes.
 */
interface MaximoWebhookPayload {
  /** Event type */
  event: MaximoWebhookEventType;
  /** Work order number (e.g., "WO-2026-ABC123") */
  wonum: string;
  /** New status (e.g., "INPRG", "COMP") */
  status?: MaximoWoStatus;
  /** Timestamp of the change (ISO 8601) */
  changedate: string;
  /** Optional: Site ID */
  siteid?: string;
  /** Optional: Asset number (train number) */
  assetnum?: string;
  /** Optional: Actual start date */
  actstart?: string;
  /** Optional: Actual finish date */
  actfinish?: string;
  /** Optional: Actual labor hours */
  actlabhrs?: number;
  /** Optional: MMS schedule ID backreference */
  mms_schedule_id?: string;
}

/**
 * Validate Maximo webhook payload
 */
function validateWebhookPayload(
  payload: unknown
): { valid: true; data: MaximoWebhookPayload } | { valid: false; error: string } {
  if (typeof payload !== 'object' || payload === null) {
    return { valid: false, error: 'Payload must be an object' };
  }

  const p = payload as Record<string, unknown>;

  // Required: event
  if (!p.event || typeof p.event !== 'string') {
    return { valid: false, error: 'Missing or invalid event field' };
  }

  const validEvents: MaximoWebhookEventType[] = [
    'wo_status_changed',
    'wo_created',
    'wo_updated',
    'wo_cancelled',
  ];
  if (!validEvents.includes(p.event as MaximoWebhookEventType)) {
    return { valid: false, error: `Invalid event type: ${p.event}` };
  }

  // Required: wonum
  if (!p.wonum || typeof p.wonum !== 'string') {
    return { valid: false, error: 'Missing or invalid wonum field' };
  }

  // Required: changedate
  if (!p.changedate || typeof p.changedate !== 'string') {
    return { valid: false, error: 'Missing or invalid changedate field' };
  }

  // Validate changedate is valid ISO 8601
  const changeDate = new Date(p.changedate);
  if (isNaN(changeDate.getTime())) {
    return { valid: false, error: 'changedate must be valid ISO 8601 format' };
  }

  // Optional: status (required for wo_status_changed)
  if (p.event === 'wo_status_changed') {
    if (!p.status || typeof p.status !== 'string') {
      return { valid: false, error: 'status is required for wo_status_changed event' };
    }

    const validStatuses: MaximoWoStatus[] = ['WAPPR', 'APPR', 'INPRG', 'COMP', 'CLOSE', 'CAN'];
    if (!validStatuses.includes(p.status as MaximoWoStatus)) {
      return { valid: false, error: `Invalid status: ${p.status}` };
    }
  }

  return {
    valid: true,
    data: {
      event: p.event as MaximoWebhookEventType,
      wonum: p.wonum as string,
      status: p.status as MaximoWoStatus | undefined,
      changedate: p.changedate as string,
      siteid: typeof p.siteid === 'string' ? p.siteid : undefined,
      assetnum: typeof p.assetnum === 'string' ? p.assetnum : undefined,
      actstart: typeof p.actstart === 'string' ? p.actstart : undefined,
      actfinish: typeof p.actfinish === 'string' ? p.actfinish : undefined,
      actlabhrs: typeof p.actlabhrs === 'number' ? p.actlabhrs : undefined,
      mms_schedule_id: typeof p.mms_schedule_id === 'string' ? p.mms_schedule_id : undefined,
    },
  };
}

/**
 * POST /integration/webhooks/maximo
 *
 * Receive CM/WO status updates from Maximo.
 *
 * This endpoint is called by Maximo when:
 * - Work order status changes (WAPPR → APPR → INPRG → COMP → CLOSE)
 * - Work order is cancelled (CAN)
 * - Actual labor hours are recorded
 *
 * The webhook updates the shadow record and locks the PM if necessary.
 *
 * @security This endpoint should be protected by Maximo webhook authentication
 * (e.g., shared secret, IP allowlist, or mutual TLS)
 *
 * @see specs/007-integration.md Section 7.4.7
 */
integrationRoutes.post('/integration/webhooks/maximo', async (c) => {
  const requestId = getRequestId(c);
  const startTime = Date.now();

  let payload: MaximoWebhookPayload;

  try {
    const body = await c.req.json();
    const validation = validateWebhookPayload(body);

    if (!validation.valid) {
      logger.warn({ requestId, error: validation.error }, 'Invalid Maximo webhook payload');
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, validation.error, requestId),
        400
      );
    }

    payload = validation.data;
  } catch (err) {
    logger.warn({ requestId, error: err }, 'Failed to parse Maximo webhook payload');
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON payload', requestId),
      400
    );
  }

  logger.info(
    { requestId, event: payload.event, wonum: payload.wonum, status: payload.status },
    'Received Maximo webhook'
  );

  // Using imported db singleton

  // Find shadow record by Maximo WO number
  const shadowRecord = await db.query.maximoShadowRecords.findFirst({
    where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
  });

  if (!shadowRecord) {
    // Check if we have an mms_schedule_id backreference
    if (payload.mms_schedule_id && isValidUuid(payload.mms_schedule_id)) {
      // Try to find shadow record by PM schedule ID
      const shadowByPm = await db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.pmScheduleId, payload.mms_schedule_id),
      });

      if (shadowByPm) {
        // Update shadow record with WO number
        await db
          .update(maximoShadowRecords)
          .set({
            maximoWoNum: payload.wonum,
            updatedAt: new Date(),
          })
          .where(eq(maximoShadowRecords.id, shadowByPm.id));

        logger.info(
          { requestId, shadowRecordId: shadowByPm.id, wonum: payload.wonum },
          'Associated Maximo WO number with existing shadow record'
        );
      }
    }

    // If still no shadow record, log and return success (idempotent)
    if (!shadowRecord) {
      logger.info(
        { requestId, wonum: payload.wonum },
        'No shadow record found for Maximo WO - may be untracked in MMS'
      );

      return c.json(
        success({
          received: true,
          processed: false,
          reason: 'No matching shadow record found',
          wonum: payload.wonum,
        }),
        200
      );
    }
  }

  // Process based on event type
  try {
    let action = 'none';
    let mmsStatusUpdated = false;
    let pmLocked = false;

    if (payload.event === 'wo_status_changed' && payload.status) {
      // Get the current shadow record (refreshed)
      const currentShadow = await db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
      });

      if (currentShadow) {
        const previousMaximoData = currentShadow.maximoData as { status?: string } | null;
        const previousStatus = previousMaximoData?.status;

        // Update shadow record with new Maximo data
        await db
          .update(maximoShadowRecords)
          .set({
            maximoData: {
              status: payload.status,
              actualStart: payload.actstart,
              actualFinish: payload.actfinish,
              actualLabor: payload.actlabhrs,
              changeDate: payload.changedate,
            },
            lastSyncAt: new Date(),
            syncStatus: 'SYNCED',
            updatedAt: new Date(),
          })
          .where(eq(maximoShadowRecords.id, currentShadow.id));

        // Map Maximo status to MMS status
        const mmsStatus = MAXIMO_TO_MMS_STATUS[payload.status];

        // Update PM schedule status
        const pmRecord = await db.query.pmSchedule.findFirst({
          where: eq(pmSchedule.id, currentShadow.pmScheduleId),
        });

        if (pmRecord) {
          const isLocked = LOCKED_MAXIMO_STATUSES.includes(payload.status);

          // Update PM schedule
          await db
            .update(pmSchedule)
            .set({
              status: mmsStatus,
              isLocked: isLocked,
              actualStartDate: payload.actstart ? payload.actstart.split('T')[0] : pmRecord.actualStartDate,
              actualEndDate: payload.actfinish ? payload.actfinish.split('T')[0] : pmRecord.actualEndDate,
              actualHours: payload.actlabhrs !== undefined
                ? payload.actlabhrs.toString()
                : pmRecord.actualHours,
              updatedAt: new Date(),
            })
            .where(eq(pmSchedule.id, pmRecord.id));

          mmsStatusUpdated = true;
          pmLocked = isLocked;

          logger.info(
            {
              requestId,
              pmScheduleId: pmRecord.id,
              previousStatus,
              newStatus: payload.status,
              mmsStatus,
              isLocked,
            },
            'Updated PM schedule from Maximo webhook'
          );
        }

        action = 'status_updated';
      }
    } else if (payload.event === 'wo_cancelled') {
      // Handle work order cancellation
      const currentShadow = await db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
      });

      if (currentShadow) {
        await db
          .update(maximoShadowRecords)
          .set({
            maximoData: {
              status: 'CAN',
              changeDate: payload.changedate,
            },
            syncStatus: 'SYNCED',
            updatedAt: new Date(),
          })
          .where(eq(maximoShadowRecords.id, currentShadow.id));

        // Update PM schedule to CANCELLED and locked
        await db
          .update(pmSchedule)
          .set({
            status: 'CANCELLED',
            isLocked: true,
            updatedAt: new Date(),
          })
          .where(eq(pmSchedule.id, currentShadow.pmScheduleId));

        action = 'wo_cancelled';
        mmsStatusUpdated = true;
        pmLocked = true;

        logger.info(
          { requestId, pmScheduleId: currentShadow.pmScheduleId, wonum: payload.wonum },
          'PM cancelled from Maximo webhook'
        );
      }
    }

    const durationMs = Date.now() - startTime;

    return c.json(
      success({
        received: true,
        processed: true,
        action,
        wonum: payload.wonum,
        event: payload.event,
        mmsStatusUpdated,
        pmLocked,
        durationMs,
      }),
      200
    );
  } catch (err) {
    logger.error({ requestId, error: err, wonum: payload.wonum }, 'Failed to process Maximo webhook');
    return c.json(
      error(
        ErrorCodes.INTERNAL_ERROR,
        'Failed to process webhook',
        requestId,
        { wonum: payload.wonum }
      ),
      500
    );
  }
});

// =============================================================================
// Sync Operations
// =============================================================================

/**
 * GET /integration/sync/stats
 *
 * Get Maximo sync statistics.
 *
 * Returns counts of shadow records by status, last sync timestamps,
 * and circuit breaker state.
 */
integrationRoutes.get('/integration/sync/stats', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    const stats = await service.getSyncStats();

    return c.json(
      success({
        pendingRecords: stats.pendingRecords,
        syncedRecords: stats.syncedRecords,
        conflictRecords: stats.conflictRecords,
        errorRecords: stats.errorRecords,
        totalRecords:
          stats.pendingRecords + stats.syncedRecords + stats.conflictRecords + stats.errorRecords,
        lastSyncAt: stats.lastSyncAt?.toISOString() ?? null,
        lastPullAt: stats.lastPullAt?.toISOString() ?? null,
        circuitBreakerState: stats.circuitBreakerState,
        isHealthy: stats.circuitBreakerState === 'CLOSED',
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to get sync stats');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to get sync statistics', requestId),
      500
    );
  }
});

/**
 * POST /integration/sync/push
 *
 * Trigger push sync (MMS → Maximo).
 *
 * Pushes all pending shadow records to Maximo, creating or updating
 * work orders as needed.
 *
 * @returns Summary of push results
 */
integrationRoutes.post('/integration/sync/push', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    logger.info({ requestId }, 'Starting push sync to Maximo');

    const result = await service.pushAllPending();

    logger.info(
      { requestId, pushed: result.pushed, errors: result.errors },
      'Push sync completed'
    );

    return c.json(
      success({
        operation: 'push',
        pushed: result.pushed,
        errors: result.errors,
        success: result.errors === 0,
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Push sync failed');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Push sync failed', requestId),
      500
    );
  }
});

/**
 * POST /integration/sync/pull
 *
 * Trigger pull sync (Maximo → MMS).
 *
 * Queries Maximo for work order status changes and updates MMS
 * PM schedules accordingly.
 *
 * @returns Summary of pull results
 */
integrationRoutes.post('/integration/sync/pull', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    logger.info({ requestId }, 'Starting pull sync from Maximo');

    const result = await service.pullFromMaximo();

    logger.info(
      {
        requestId,
        processed: result.processed,
        updated: result.updated,
        conflicts: result.conflicts,
        errors: result.errors,
      },
      'Pull sync completed'
    );

    return c.json(
      success({
        operation: 'pull',
        processed: result.processed,
        updated: result.updated,
        conflicts: result.conflicts,
        errors: result.errors,
        success: result.errors === 0,
        details: result.details,
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Pull sync failed');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Pull sync failed', requestId),
      500
    );
  }
});

/**
 * POST /integration/sync/full
 *
 * Trigger full bidirectional sync.
 *
 * Performs both push (MMS → Maximo) and pull (Maximo → MMS) operations.
 *
 * @returns Combined sync results
 */
integrationRoutes.post('/integration/sync/full', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    logger.info({ requestId }, 'Starting full bidirectional sync');

    // Push first, then pull
    const pushResult = await service.pushAllPending();
    const pullResult = await service.pullFromMaximo();

    logger.info(
      {
        requestId,
        push: { pushed: pushResult.pushed, errors: pushResult.errors },
        pull: {
          processed: pullResult.processed,
          updated: pullResult.updated,
          conflicts: pullResult.conflicts,
          errors: pullResult.errors,
        },
      },
      'Full sync completed'
    );

    return c.json(
      success({
        operation: 'full',
        push: {
          pushed: pushResult.pushed,
          errors: pushResult.errors,
        },
        pull: {
          processed: pullResult.processed,
          updated: pullResult.updated,
          conflicts: pullResult.conflicts,
          errors: pullResult.errors,
        },
        success: pushResult.errors === 0 && pullResult.errors === 0,
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Full sync failed');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Full sync failed', requestId),
      500
    );
  }
});

// =============================================================================
// Conflict Management
// =============================================================================

/**
 * GET /integration/conflicts
 *
 * List all shadow records with sync conflicts.
 *
 * Query Parameters:
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 *
 * @returns Paginated list of conflicts with PM details
 */
integrationRoutes.get('/integration/conflicts', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  try {
    const result = await service.listShadowRecords(
      { syncStatus: 'CONFLICT' },
      { page: pagination.page, pageSize: pagination.pageSize }
    );

    // Transform to API response format
    const conflicts = result.data.map((item) => ({
      id: item.shadowRecord.id,
      pmScheduleId: item.shadowRecord.pmScheduleId,
      maximoWoNum: item.shadowRecord.maximoWoNum,
      syncStatus: item.shadowRecord.syncStatus,
      lastSyncAt: item.shadowRecord.lastSyncAt?.toISOString() ?? null,
      lastSyncError: item.shadowRecord.lastSyncError,
      mmsData: item.shadowRecord.mmsDataSnapshot,
      maximoData: item.shadowRecord.maximoData,
      pmSchedule: {
        id: item.pmSchedule.id,
        trainId: item.pmSchedule.trainId,
        trainNumber: item.pmSchedule.train?.trainNumber,
        pmTypeCode: item.pmSchedule.pmType?.pmCode,
        pmTypeName: item.pmSchedule.pmType?.pmName,
        targetDate: item.pmSchedule.targetDate,
        status: item.pmSchedule.status,
        depotCode: item.pmSchedule.depot?.code,
      },
      createdAt: item.shadowRecord.createdAt?.toISOString() ?? new Date().toISOString(),
      updatedAt: item.shadowRecord.updatedAt?.toISOString() ?? new Date().toISOString(),
    }));

    return c.json(
      paginatedSuccess(conflicts, {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      }, { durationMs: getRequestDuration(c) })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to list conflicts');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to list conflicts', requestId),
      500
    );
  }
});

/**
 * GET /integration/conflicts/:id
 *
 * Get details of a specific conflict.
 *
 * @param id - Shadow record ID
 * @returns Conflict details with MMS and Maximo data comparison
 */
integrationRoutes.get('/integration/conflicts/:id', async (c) => {
  const requestId = getRequestId(c);
  const id = c.req.param('id');

  if (!isValidUuid(id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid conflict ID format', requestId),
      400
    );
  }

  // Using imported db singleton

  try {
    const shadowRecord = await db.query.maximoShadowRecords.findFirst({
      where: eq(maximoShadowRecords.id, id),
      with: {
        pmScheduleEntry: {
          with: {
            train: true,
            pmType: true,
            assignedDepot: true,
          },
        },
      },
    });

    if (!shadowRecord) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'Conflict not found', requestId),
        404
      );
    }

    if (shadowRecord.syncStatus !== 'CONFLICT') {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Record is not in conflict state', requestId, {
          currentStatus: shadowRecord.syncStatus,
        }),
        400
      );
    }

    const mmsData = shadowRecord.mmsDataSnapshot as {
      trainId: string;
      pmTypeCode: string;
      targetDate: string;
      status: string;
      assignedDepotId?: string;
      assignedHours?: string;
    } | null;

    const maximoData = shadowRecord.maximoData as {
      status?: string;
      schedStart?: string;
      schedFinish?: string;
      actualStart?: string;
      actualFinish?: string;
      actualLabor?: number;
      changeDate?: string;
    } | null;

    return c.json(
      success({
        id: shadowRecord.id,
        pmScheduleId: shadowRecord.pmScheduleId,
        maximoWoNum: shadowRecord.maximoWoNum,
        syncStatus: shadowRecord.syncStatus,
        lastSyncAt: shadowRecord.lastSyncAt?.toISOString() ?? null,
        mmsData: mmsData ? {
          targetDate: mmsData.targetDate,
          status: mmsData.status,
          assignedHours: mmsData.assignedHours,
        } : null,
        maximoData: maximoData ? {
          status: maximoData.status,
          statusLabel: maximoData.status
            ? MAXIMO_STATUS_LABELS[maximoData.status as MaximoWoStatus]
            : null,
          schedStart: maximoData.schedStart,
          schedFinish: maximoData.schedFinish,
          actualStart: maximoData.actualStart,
          actualFinish: maximoData.actualFinish,
          actualLabor: maximoData.actualLabor,
          changeDate: maximoData.changeDate,
        } : null,
        pmSchedule: {
          id: shadowRecord.pmScheduleEntry.id,
          trainId: shadowRecord.pmScheduleEntry.trainId,
          trainNumber: shadowRecord.pmScheduleEntry.train?.trainNumber,
          pmTypeCode: shadowRecord.pmScheduleEntry.pmType?.pmCode,
          pmTypeName: shadowRecord.pmScheduleEntry.pmType?.pmName,
          targetDate: shadowRecord.pmScheduleEntry.targetDate,
          currentStatus: shadowRecord.pmScheduleEntry.status,
